module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
assign N = 8;
parameter S = 16;
reg mul_en_out_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) mul_en_out_reg <= {S{1'b0}};
    else        mul_en_out_reg <= {mul_en_out_reg[S-1:0], mul_en_in};
end
assign mul_en_out = mul_en_out_reg[N-1];
reg [7:0] mul_a_reg;
reg [7:0] mul_b_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= {8{1'b0}};
        mul_b_reg <= {8{1'b0}};
    end
    else begin
        mul_a_reg <= mul_en_in ? mul_a : mul_a_reg;
        mul_b_reg <= mul_en_in ? mul_b : mul_b_reg;
    end
end
wire [7:0] a = mul_a_reg;
wire [7:0] b = mul_b_reg;
wire [7:0] x = {8{b[0]}};
wire [7:0] y = {8{b[1]}};
wire [7:0] z = {8{b[2]}};
wire [7:0] p0 = (a & {8{b[0]}}); 
wire [7:0] p1 = (a & {8{b[1]}}); 
wire [7:0] p2 = (a & {8{b[2]}}); 
wire [8:0] s0 = {p0[7], p0[7:1], 1'b0};
wire [8:0] s1 = {p1[7], p1[7:1], 1'b0} + p0;
wire [8:0] s2 = {p2[7], p2[7:1], 1'b0} + s1;
wire [15:0] prod_reg;
wire [15:0] sum[7:0];
reg [15:0] temp[7:0];
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        temp[0] <= {S{1'b0}};
        temp[1] <= {S{1'b0}};
        temp[2] <= {S{1'b0}};
        temp[3] <= {S{1'b0}};
        temp[4] <= {S{1'b0}};
        temp[5] <= {S{1'b0}};
        temp[6] <= {S{1'b0}};
        temp[7] <= {S{1'b0}};
    end
    else begin
        temp[0] <= {p0[7], p0[7:1], 1'b0};
        temp[1] <= s0;
        temp[2] <= s1;
        temp[3] <= s2;
        temp[4] <= {p3[7], p3[7:1], 1'b0};
        temp[5] <= {p4[7], p4[7:1], 1'b0};
        temp[6] <= {p5[7], p5[7:1], 1'b0};
        temp[7] <= prod_reg;
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= {8{1'b0}};
        mul_b_reg <= {8{1'b0}};
    end
    else begin
        mul_a_reg <= mul_en_in ? mul_a : mul_a_reg;
        mul_b_reg <= mul_en_in ? mul_b : mul_b_reg;
    end
end
wire [15:0] sum[7:0];
assign sum[0] = temp[0];
assign sum[1] = temp[1] + temp[0];
assign sum[2] = temp[2] + temp[1];
assign sum[3] = temp[3] + temp[2];
assign sum[4] = temp[4] + temp[3];
assign sum[5] = temp[5] + temp[4];
assign sum[6] = temp[6] + temp[5];
assign sum[7] = temp[7] + temp[6];
assign prod_reg = sum[7];
assign mul_out = mul_en_out ? prod_reg : {S{1'b0}};
endmodule
